import React, { useState, useRef, useEffect, useMemo } from 'react';
import Fuse from 'fuse.js';
import { motion, AnimatePresence } from 'framer-motion';
import {
  MessageSquare,
  Search,
  History,
  Mic,
  Square,
  Play,
  Sparkles,
  Trash2,
  Calendar,
  ChevronRight,
  Wind,
  BarChart3,
  X,
  LayoutDashboard,
  LogOut,
  ArrowLeft,
  User,
  ClipboardList,
  Plus
} from 'lucide-react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  AreaChart,
  Area
} from 'recharts';
import FinanceiroView from './components/FinanceiroView';
import DiarioEmocionalView from './components/DiarioEmocionalView';
import './index.css';

const API_BASE_URL = 'http://localhost:5000';

function App() {
  // Autenticação e Perfis
  const [usuario, setUsuario] = useState(() => {
    const saved = localStorage.getItem('usuario');
    return saved ? JSON.parse(saved) : null;
  });

  const [authMode, setAuthMode] = useState('login'); // 'login' or 'cadastro'
  const [authTipo, setAuthTipo] = useState('paciente'); // 'paciente' or 'psicologo'
  const [authNome, setAuthNome] = useState('');
  const [authEmail, setAuthEmail] = useState('');
  const [authSenha, setAuthSenha] = useState('');
  const [authPsicologoId, setAuthPsicologoId] = useState('');
  const [listaPsicologos, setListaPsicologos] = useState([]);

  // Estados do Chat e Histórico (Paciente)
  const [gravando, setGravando] = useState(false);
  const [transcricao, setTranscricao] = useState('');
  const [exercicio, setExercicio] = useState('');
  const [carregando, setCarregando] = useState(false);
  const [historico, setHistorico] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [sessaoAtiva, setSessaoAtiva] = useState(null);
  const [currentView, setCurrentView] = useState('app'); // 'app', 'dashboard', 'agenda', 'financeiro', 'prontuario'
  const [showSOS, setShowSOS] = useState(false);
  const [breathingStep, setBreathingStep] = useState('Inspire');
  const [falando, setFalando] = useState(false);

  // Estados do Psicólogo
  const [listaPacientes, setListaPacientes] = useState([]);
  const [pacienteSelecionado, setPacienteSelecionado] = useState(null);

  // Cadastro de Paciente pelo Psicólogo
  const [showNovoPacienteForm, setShowNovoPacienteForm] = useState(false);
  const [novoPacNome, setNovoPacNome] = useState('');
  const [novoPacEmail, setNovoPacEmail] = useState('');
  const [novoPacSenha, setNovoPacSenha] = useState('');

  // Estados para Agenda (Fase 3)
  const [listaConsultas, setListaConsultas] = useState([]);
  const [dataSelecionada, setDataSelecionada] = useState('');
  const [horariosDisponiveis, setHorariosDisponiveis] = useState([]);
  const [horarioSelecionado, setHorarioSelecionado] = useState('');
  const [obsConsulta, setObsConsulta] = useState('');
  const [pacienteConsultaId, setPacienteConsultaId] = useState(''); // Usado na visão geral do Psicólogo para agendar

  // Estados para Financeiro (Fase 4)
  const [financeiroData, setFinanceiroData] = useState({ lancamentos: [], resumo: { total_receitas: 0, total_despesas: 0, lucro_liquido: 0 } });
  const [listaPacotes, setListaPacotes] = useState([]);

  // Prontuário IA Consolidado (Novo)
  const [prontuarioConteudo, setProntuarioConteudo] = useState('');
  const [prontuarioData, setProntuarioData] = useState('');
  const [gerandoProntuario, setGerandoProntuario] = useState(false);

  // Notas Clínicas do Psicólogo
  const [listaNotas, setListaNotas] = useState([]);
  const [novaNotaConteudo, setNovaNotaConteudo] = useState('');
  const [carregandoNotas, setCarregandoNotas] = useState(false);
  const [abordagemSelecionada, setAbordagemSelecionada] = useState('padrao');

  // Insights IA de Risco (Novo)
  const [insightsIA, setInsightsIA] = useState({ alertas: [], foco: '', humor_trend: '' });
  const [carregandoInsights, setCarregandoInsights] = useState(false);

  // Tarefas Clínicas / Lições de Casa (Novo)
  const [listaTarefas, setListaTarefas] = useState([]);
  const [novoTituloTarefa, setNovoTituloTarefa] = useState('');
  const [novaDescricaoTarefa, setNovaDescricaoTarefa] = useState('');
  const [carregandoTarefas, setCarregandoTarefas] = useState(false);

  // Anamnese Clínica (Primeira Consulta)
  const [anamneseData, setAnamneseData] = useState({
    queixa_principal: '',
    historico_sintomas: '',
    historico_familiar: '',
    historico_medico: '',
    relacionamentos_sociais: '',
    expectativas_terapia: '',
    observacoes_gerais: ''
  });
  const [carregandoAnamnese, setCarregandoAnamnese] = useState(false);
  const [salvandoAnamnese, setSalvandoAnamnese] = useState(false);

  // Avaliações Psicométricas
  const [listaAvaliacoes, setListaAvaliacoes] = useState([]);
  const [carregandoAvaliacoes, setCarregandoAvaliacoes] = useState(false);
  const [novaAvaliacaoTipo, setNovaAvaliacaoTipo] = useState('PHQ-9');
  const [respostasAvaliacao, setRespostasAvaliacao] = useState({});

  // Resumo IA (Psicólogo)
  const [resumoPreSessao, setResumoPreSessao] = useState('');
  const [gerandoResumo, setGerandoResumo] = useState(false);

  // TCLE
  const [tcleAssinado, setTcleAssinado] = useState(true);
  const [dataAssinaturaTcle, setDataAssinaturaTcle] = useState(null);
  const [carregandoTcle, setCarregandoTcle] = useState(false);

  // Plano Terapeutico
  const [planoTerapeutico, setPlanoTerapeutico] = useState({ id: null, objetivos: '', intervencoes: '', frequencia: 'Semanal', data_criacao: null });
  const [editandoPlano, setEditandoPlano] = useState(false);

  const mediaRecorderRef = useRef(null);
  const audioChunksRef = useRef([]);
  const audioContextRef = useRef(null);

  // Carregar psicólogos para a tela de cadastro de pacientes
  useEffect(() => {
    if (authMode === 'cadastro' && authTipo === 'paciente') {
      fetch(`${API_BASE_URL}/psicologos`)
        .then(res => res.json())
        .then(data => {
          setListaPsicologos(data);
          if (data.length > 0) setAuthPsicologoId(data[0].id);
        })
        .catch(err => console.error("Erro ao buscar psicólogos:", err));
    }
  }, [authMode, authTipo]);

  // Carregar dados gerais ao iniciar
  useEffect(() => {
    if (usuario) {
      fetchConsultas();
      fetchFinanceiro();
      if (usuario.tipo === 'paciente') {
        fetchHistorico();
        fetchPacotes();
        fetchTarefas(usuario.id);
        fetchTCLE(usuario.id);
      } else if (usuario.tipo === 'psicologo') {
        fetchPacientes();
      }
    }
  }, [usuario]);

  // Carregar histórico, pacotes e prontuário IA do paciente selecionado
  useEffect(() => {
    if (usuario && usuario.tipo === 'psicologo' && pacienteSelecionado) {
      fetchHistorico(pacienteSelecionado.id);
      fetchPacotes(pacienteSelecionado.id);
      fetchConsultas();
      fetchProntuarioIA(pacienteSelecionado.id);
      fetchNotas(pacienteSelecionado.id);
      fetchInsights(pacienteSelecionado.id);
      fetchTarefas(pacienteSelecionado.id);
      fetchAnamnese(pacienteSelecionado.id);
      fetchAvaliacoes(pacienteSelecionado.id);
    } else {
      setHistorico([]);
      setProntuarioConteudo('');
      setProntuarioData('');
      setListaNotas([]);
      setListaTarefas([]);
      setInsightsIA({ alertas: [], foco: '', humor_trend: '' });
      setAnamneseData({
        queixa_principal: '',
        historico_sintomas: '',
        historico_familiar: '',
        historico_medico: '',
        relacionamentos_sociais: '',
        expectativas_terapia: '',
        observacoes_gerais: ''
      });
      setListaAvaliacoes([]);
      setRespostasAvaliacao({});
    }
    setSessaoAtiva(null);
    setTranscricao('');
    setExercicio('');
    setCurrentView('app'); // Reseta a aba interna ao trocar paciente
    setShowNovoPacienteForm(false); // Fecha cadastro se abrir paciente
  }, [pacienteSelecionado]);

  // Carregar horários livres quando a data mudar
  useEffect(() => {
    if (dataSelecionada) {
      fetchHorariosDisponiveis(dataSelecionada);
    } else {
      setHorariosDisponiveis([]);
    }
  }, [dataSelecionada]);

  // Fetch Handlers

  const fetchHistorico = async (pacienteId = null) => {
    if (!usuario) return;
    try {
      let url = `${API_BASE_URL}/historico`;
      if (usuario.tipo === 'psicologo' && pacienteId) {
        url += `?paciente_id=${pacienteId}`;
      }

      const resp = await fetch(url, {
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      const data = await resp.json();
      setHistorico(data.map(item => ({
        ...item,
        sentimento: item.sentimento || 'Neutro'
      })));
    } catch (err) {
      console.error("Erro ao carregar histórico:", err);
    }
  };

  const fetchPacientes = async () => {
    if (!usuario || usuario.tipo !== 'psicologo') return;
    try {
      const resp = await fetch(`${API_BASE_URL}/pacientes`, {
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      const data = await resp.json();
      setListaPacientes(data);
    } catch (err) {
      console.error("Erro ao carregar pacientes:", err);
    }
  };

  const fetchConsultas = async () => {
    if (!usuario) return;
    try {
      let url = `${API_BASE_URL}/consultas`;
      if (usuario.tipo === 'psicologo' && pacienteSelecionado) {
        url += `?paciente_id=${pacienteSelecionado.id}`;
      }

      const resp = await fetch(url, {
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      const data = await resp.json();
      setListaConsultas(data);
    } catch (err) {
      console.error("Erro ao carregar consultas:", err);
    }
  };

  const fetchHorariosDisponiveis = async (dataStr) => {
    if (!usuario || !dataStr) return;
    const psicologoId = usuario.tipo === 'paciente' ? usuario.psicologo_id : usuario.id;

    try {
      const resp = await fetch(`${API_BASE_URL}/horarios-disponiveis?psicologo_id=${psicologoId}&data=${dataStr}`, {
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      const data = await resp.json();
      setHorariosDisponiveis(data);
      setHorarioSelecionado('');
    } catch (err) {
      console.error("Erro ao buscar horários livres:", err);
    }
  };

  const fetchProntuarioIA = async (pacienteId) => {
    if (!usuario || usuario.tipo !== 'psicologo' || !pacienteId) return;
    try {
      const resp = await fetch(`${API_BASE_URL}/paciente/${pacienteId}/prontuario-ia`, {
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });
      if (resp.status === 401) {
        handleLogout();
        return;
      }
      const data = await resp.json();
      setProntuarioConteudo(data.conteudo || '');
      setProntuarioData(data.data_atualizacao || '');
    } catch (err) {
      console.error("Erro ao buscar prontuário IA:", err);
    }
  };

  const fetchNotas = async (pacienteId) => {
    if (!usuario || usuario.tipo !== 'psicologo' || !pacienteId) return;
    setCarregandoNotas(true);
    try {
      const resp = await fetch(`${API_BASE_URL}/paciente/${pacienteId}/notas`, {
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });
      if (resp.status === 401) {
        handleLogout();
        return;
      }
      const data = await resp.json();
      if (resp.ok) {
        setListaNotas(data);
      } else {
        console.error("Erro ao buscar notas:", data.erro);
      }
    } catch (err) {
      console.error("Erro de conexão ao buscar notas:", err);
    } finally {
      setCarregandoNotas(false);
    }
  };

  const handleAdicionarNota = async (e) => {
    e.preventDefault();
    if (!usuario || usuario.tipo !== 'psicologo' || !pacienteSelecionado || !novaNotaConteudo.trim()) return;

    try {
      const resp = await fetch(`${API_BASE_URL}/paciente/${pacienteSelecionado.id}/notas`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${usuario.token}`
        },
        body: JSON.stringify({ conteudo: novaNotaConteudo })
      });
      const data = await resp.json();
      if (resp.ok) {
        setListaNotas([data.nota, ...listaNotas]);
        setNovaNotaConteudo('');
      } else {
        alert(data.erro || "Erro ao adicionar nota");
      }
    } catch (err) {
      console.error("Erro de conexão ao criar nota:", err);
      alert("Erro ao conectar com o servidor.");
    }
  };

  const handleRemoverNota = async (notaId) => {
    if (!usuario || usuario.tipo !== 'psicologo' || !window.confirm("Deseja realmente excluir esta nota? Ela não fará mais parte do prontuário inteligente.")) return;

    try {
      const resp = await fetch(`${API_BASE_URL}/notas/${notaId}`, {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });
      const data = await resp.json();
      if (resp.ok) {
        setListaNotas(listaNotas.filter(n => n.id !== notaId));
      } else {
        alert(data.erro || "Erro ao excluir nota");
      }
    } catch (err) {
      console.error("Erro de conexão ao remover nota:", err);
      alert("Erro ao conectar com o servidor.");
    }
  };

  const fetchInsights = async (pacienteId) => {
    if (!usuario || usuario.tipo !== 'psicologo' || !pacienteId) return;
    setCarregandoInsights(true);
    try {
      const resp = await fetch(`${API_BASE_URL}/paciente/${pacienteId}/insights`, {
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });
      if (resp.status === 401) {
        handleLogout();
        return;
      }
      const data = await resp.json();
      setInsightsIA(data);
    } catch (err) {
      console.error("Erro ao buscar insights IA:", err);
    } finally {
      setCarregandoInsights(false);
    }
  };

  const fetchTarefas = async (pacienteId) => {
    if (!usuario || !pacienteId) return;
    setCarregandoTarefas(true);
    try {
      const resp = await fetch(`${API_BASE_URL}/paciente/${pacienteId}/tarefas`, {
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });
      if (resp.status === 401) {
        handleLogout();
        return;
      }
      const data = await resp.json();
      if (resp.ok) {
        setListaTarefas(data);
      } else {
        console.error("Erro ao buscar tarefas:", data.erro);
      }
    } catch (err) {
      console.error("Erro de conexão ao buscar tarefas:", err);
    } finally {
      setCarregandoTarefas(false);
    }
  };

  const handleAdicionarTarefa = async (e) => {
    e.preventDefault();
    if (!usuario || usuario.tipo !== 'psicologo' || !pacienteSelecionado || !novoTituloTarefa.trim() || !novaDescricaoTarefa.trim()) return;

    try {
      const resp = await fetch(`${API_BASE_URL}/paciente/${pacienteSelecionado.id}/tarefas`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${usuario.token}`
        },
        body: JSON.stringify({
          titulo: novoTituloTarefa,
          descricao: novaDescricaoTarefa
        })
      });
      const data = await resp.json();
      if (resp.ok) {
        setListaTarefas([data.tarefa, ...listaTarefas]);
        setNovoTituloTarefa('');
        setNovaDescricaoTarefa('');
        alert("Tarefa prescrita e enviada ao paciente com sucesso!");
      } else {
        alert(data.erro || "Erro ao prescrever tarefa");
      }
    } catch (err) {
      console.error("Erro de conexão ao criar tarefa:", err);
      alert("Erro ao conectar com o servidor.");
    }
  };

  const handleConcluirTarefa = async (tarefaId, concluidaStatus) => {
    try {
      const resp = await fetch(`${API_BASE_URL}/tarefas/${tarefaId}/concluir`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${usuario.token}`
        },
        body: JSON.stringify({ concluida: concluidaStatus })
      });
      const data = await resp.json();
      if (resp.ok) {
        setListaTarefas(listaTarefas.map(t => t.id === tarefaId ? { ...t, concluida: concluidaStatus, data_conclusao: data.data_conclusao } : t));
      } else {
        alert(data.erro || "Erro ao atualizar status da tarefa");
      }
    } catch (err) {
      console.error("Erro de conexão ao atualizar tarefa:", err);
    }
  };

  const handleRemoverTarefa = async (tarefaId) => {
    if (!usuario || usuario.tipo !== 'psicologo' || !window.confirm("Deseja realmente excluir esta tarefa?")) return;

    try {
      const resp = await fetch(`${API_BASE_URL}/tarefas/${tarefaId}`, {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });
      const data = await resp.json();
      if (resp.ok) {
        setListaTarefas(listaTarefas.filter(t => t.id !== tarefaId));
      } else {
        alert(data.erro || "Erro ao excluir tarefa");
      }
    } catch (err) {
      console.error("Erro de conexão ao remover tarefa:", err);
      alert("Erro ao conectar com o servidor.");
    }
  };

  const handleExportarPDF = () => {
    if (!pacienteSelecionado || !prontuarioConteudo) {
      alert("Gere o prontuário consolidado com IA antes de exportar.");
      return;
    }

    const printWindow = window.open('', '_blank');

    // Formatar as notas clínicas
    let notasHTML = "";
    if (listaNotas.length === 0) {
      notasHTML = "<p>Nenhuma anotação de sessão presencial registrada.</p>";
    } else {
      listaNotas.forEach(n => {
        notasHTML += `
          <div class="nota-item">
            <div class="nota-date">${n.data}</div>
            <p>${n.conteudo.replace(/\n/g, '<br>')}</p>
          </div>
        `;
      });
    }

    // Formatar prontuário IA (convertendo markdown simples para HTML)
    let prontuarioHTML = prontuarioConteudo
      .replace(/### (.*)/g, '<h3>$1</h3>')
      .replace(/## (.*)/g, '<h2>$1</h2>')
      .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
      .replace(/^- (.*)/gm, '<li>$1</li>')
      .replace(/\n/g, '<br>');

    const title = `Prontuario_Clinico_${pacienteSelecionado.nome.replace(/\s+/g, '_')}`;
    const dataEmissao = `${new Date().toLocaleDateString('pt-BR')} ${new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}`;

    printWindow.document.write(`
      <html>
        <head>
          <title>${title}</title>
          <style>
            @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;600;700&display=swap');
            body {
              font-family: 'Inter', sans-serif;
              color: #1e293b;
              padding: 2rem;
              line-height: 1.6;
              font-size: 11pt;
            }
            .header-doc {
              text-align: center;
              border-bottom: 2px solid #8b5cf6;
              padding-bottom: 1.5rem;
              margin-bottom: 2rem;
            }
            .header-doc h1 {
              margin: 0;
              font-size: 20pt;
              color: #8b5cf6;
            }
            .header-doc p {
              margin: 5px 0 0 0;
              font-size: 10pt;
              color: #64748b;
            }
            .meta-grid {
              display: grid;
              grid-template-columns: 1fr 1fr;
              gap: 10px;
              margin-bottom: 2rem;
              background: #f8fafc;
              padding: 1rem;
              border-radius: 8px;
              border: 1px solid #e2e8f0;
              font-size: 10pt;
            }
            .meta-item strong {
              color: #475569;
            }
            h2 {
              font-size: 14pt;
              color: #1e293b;
              border-bottom: 1px solid #e2e8f0;
              padding-bottom: 5px;
              margin-top: 2rem;
            }
            h3 {
              font-size: 12pt;
