      dominante: historico.length > 0 ? Object.entries(historico.reduce((acc, curr) => {
        acc[curr.sentimento] = (acc[curr.sentimento] || 0) + 1;
        return acc;
      }, {})).sort((a, b) => b[1] - a[1])[0][0] : 'Nenhum'
    };
  }, [historico]);

  const SOSOverlay = () => (
    <motion.div className="sos-overlay" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
