                ) : currentView === 'avaliacoes' ? (
                  AvaliacoesView()
                ) : currentView === 'plano_terapeutico' ? (
                  PlanoTerapeuticoView()
                ) : (
                  <div style={{ display: 'flex', gap: '2rem' }}>
                    {/* Barra de Busca Dinâmica Interna */}
                    <div style={{ width: '30%', display: 'flex', flexDirection: 'column', gap: '12px' }}>
                      <div className="search-container" style={{ marginTop: 0 }}>
                        <Search className="search-icon" size={16} />
                        <input
                          type="text"
                          placeholder="Buscar registros..."
                          value={searchTerm}
                          onChange={(e) => setSearchTerm(e.target.value)}
                          style={{ padding: '0.6rem 0.8rem 0.6rem 2.2rem', fontSize: '0.85rem' }}
                        />
                      </div>
                      <div style={{ maxHeight: '400px', overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: '8px' }}>
                        {filteredHistorico.map((item) => (
                          <div
                            key={item.id}
                            className={`history-item ${sessaoAtiva?.id === item.id ? 'active' : ''}`}
                            onClick={() => selecionarSessao(item)}
                            style={{ padding: '0.8rem' }}
                          >
                            <div className="date" style={{ fontSize: '0.65rem' }}>
                              {item.data}
                            </div>
                            <div className="preview" style={{ fontSize: '0.8rem' }}>{item.transcricao}</div>
                          </div>
                        ))}
                      </div>
                    </div>

                    {/* Ficha Clínica Selecionada */}
                    <div style={{ flex: 1 }}>
                      {exercicio ? (
                        <motion.div
                          className="result-card professional-card"
                          initial={{ opacity: 0, y: 10 }}
                          animate={{ opacity: 1, y: 0 }}
                          style={{ margin: 0, background: 'rgba(15, 23, 42, 0.4)' }}
                        >
                          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                            <h3 style={{ margin: 0, fontSize: '0.85rem', display: 'flex', alignItems: 'center' }}>
                              <Sparkles size={14} style={{ marginRight: 8 }} /> Ficha Evolutiva (IA)
                            </h3>
                            <div style={{ display: 'flex', gap: '8px' }}>
                              <button
                                onClick={falando ? pararDeFalar : () => falar(exercicio)}
                                className="audio-control-btn"
                                title={falando ? "Parar áudio" : "Ouvir laudo"}
                              >
                                {falando ? <Square size={14} fill="currentColor" /> : <Play size={14} fill="currentColor" />}
                              </button>
                              <button className="logout-btn" style={{ borderColor: 'rgba(239, 68, 68, 0.2)' }} onClick={(e) => deleteSessao(e, sessaoAtiva.id)}>
                                <Trash2 size={12} /> Apagar
                              </button>
                            </div>
                          </div>
                          <div className="result-card" style={{ background: 'rgba(0,0,0,0.2)', borderLeftColor: 'rgba(255,255,255,0.1)', padding: '1rem', marginBottom: '1.5rem' }}>
                            <h4 style={{ fontSize: '0.75rem', color: 'var(--text-muted)', textTransform: 'uppercase', marginBottom: '6px' }}>Relato do Paciente</h4>
                            <p style={{ fontSize: '0.95rem', color: '#e2e8f0', fontStyle: 'italic' }}>"{transcricao}"</p>
                          </div>
                          {formatarAnalise(exercicio)}
                        </motion.div>
                      ) : (
                        <div style={{ textAlign: 'center', padding: '4rem 2rem', background: 'rgba(255,255,255,0.02)', borderRadius: '1.5rem', border: '1px solid var(--glass-border)' }}>
                          <MessageSquare size={32} style={{ color: 'var(--accent)', opacity: 0.4, marginBottom: '1rem' }} />
                          <h4 style={{ margin: 0, color: 'var(--text-main)' }}>Selecione um desabafo na coluna esquerda</h4>
                          <p style={{ color: 'var(--text-muted)', fontSize: '0.85rem', marginTop: '0.5rem' }}>
                            Você poderá verificar a transcrição do áudio, gatilhos identificados e orientações teóricas da IA.
                          </p>
                        </div>
                      )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </main>
      </div>
    );
  }

  const TCLEModal = () => (
    <div style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(15,23,42,0.95)', zIndex: 9999, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '20px' }}>
      <div style={{ background: 'var(--card-bg)', border: '1px solid var(--glass-border)', borderRadius: '1.5rem', padding: '2.5rem', maxWidth: '650px', width: '100%', maxHeight: '90vh', overflowY: 'auto' }}>
        <h2 style={{ color: 'white', marginBottom: '1rem', fontFamily: 'Outfit, sans-serif' }}>Termo de Consentimento Livre e Esclarecido (TCLE)</h2>
        <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem', marginBottom: '1.5rem' }}>
          Para iniciarmos seu acompanhamento terapêutico mediado por nossa plataforma, é necessária a leitura e o aceite do nosso TCLE, conforme as normas do Conselho Federal de Psicologia.
        </p>
        <div style={{ background: 'rgba(0,0,0,0.3)', padding: '1.5rem', borderRadius: '1rem', color: '#cbd5e1', fontSize: '0.85rem', lineHeight: '1.6', height: '250px', overflowY: 'auto', marginBottom: '2rem', border: '1px solid rgba(255,255,255,0.05)' }}>
          <p><strong>1. Natureza do Serviço:</strong> O atendimento psicológico realizado nesta plataforma utiliza inteligência artificial como ferramenta auxiliar para transcrição e resumo de sessões, garantindo a confidencialidade e o sigilo profissional.</p>
          <p><strong>2. Sigilo Profissional:</strong> Todas as informações trocadas durante as sessões e registradas no aplicativo são sigilosas e protegidas por criptografia, em conformidade com o Código de Ética Profissional do Psicólogo e a LGPD (Lei Geral de Proteção de Dados).</p>
          <p><strong>3. Limitações em Caso de Emergência:</strong> A plataforma e a comunicação assíncrona não são adequadas para situações de emergência (como risco de vida, surtos ou ideação suicida imediata). Nestes casos, o paciente deve buscar atendimento de emergência local (SAMU, CVV 188).</p>
          <p><strong>4. Consentimento para Uso de IA:</strong> Concordo que os áudios e textos inseridos na plataforma podem ser processados por algoritmos fechados de Inteligência Artificial para fins exclusivos do meu tratamento e sob a supervisão do meu psicólogo.</p>
          <p><strong>5. Gravação de Sessões:</strong> É proibida a gravação audiovisual e em áudio das sessões em vídeo (se houver) por parte do paciente sem autorização prévia por escrito.</p>
        </div>

        <button 
          className="btn-primary" 
          onClick={handleAssinarTCLE} 
          disabled={carregandoTcle}
          style={{ width: '100%', padding: '1rem', fontSize: '1rem', fontWeight: 'bold' }}
        >
          {carregandoTcle ? 'Registrando...' : 'Li e Concordo com os Termos'}
        </button>
      </div>
    </div>
  );

  // VISTA 3: Visão do Paciente (Chat, Gravação e Histórico)
  return (
    <div className="app-wrapper">
      {!tcleAssinado && <TCLEModal />}
      <aside className="sidebar">
        <div className="user-profile-header">
          <div className="user-info">
            <span className="user-name">{usuario.nome}</span>
            <span className="user-role">Paciente</span>
          </div>
          <button className="logout-btn" onClick={handleLogout}>
            <LogOut size={14} />
          </button>
        </div>

        <div className="sidebar-header">
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
            <h2 style={{ margin: 0 }}><History size={20} style={{ marginRight: 8 }} /> Histórico</h2>
            <button className="sos-btn-small" onClick={() => setShowSOS(true)} title="Modo SOS / Respiração">
              <Wind size={18} />
            </button>
          </div>
          <button
            className={`nav-btn ${currentView === 'dashboard' ? 'active' : ''}`}
            onClick={() => setCurrentView('dashboard')}
            style={{ marginBottom: '8px' }}
          >
            <BarChart3 size={18} style={{ marginRight: 8 }} /> Ver Evolução
          </button>
          <button
            className={`nav-btn ${currentView === 'agenda' ? 'active' : ''}`}
            onClick={() => { setCurrentView('agenda'); fetchConsultas(); }}
            style={{ marginBottom: '8px' }}
          >
            <Calendar size={18} style={{ marginRight: 8 }} /> Minhas Consultas
          </button>
          <button
            className={`nav-btn ${currentView === 'financeiro' ? 'active' : ''}`}
            onClick={() => { setCurrentView('financeiro'); fetchPacotes(); fetchFinanceiro(); }}
            style={{ marginBottom: '8px' }}
          >
            <BarChart3 size={18} style={{ marginRight: 8 }} /> Meus Pagamentos
          </button>
          <button
            className={`nav-btn ${currentView === 'tarefas' ? 'active' : ''}`}
            onClick={() => { setCurrentView('tarefas'); fetchTarefas(usuario.id); }}
            style={{ marginBottom: '8px' }}
          >
            <ClipboardList size={18} style={{ marginRight: 8 }} /> Minhas Tarefas
          </button>
          <button
            className={`nav-btn ${currentView === 'diario' ? 'active' : ''}`}
            onClick={() => { setCurrentView('diario'); fetchDiario(); }}
            style={{ marginBottom: '1rem' }}
          >
            <MessageSquare size={18} style={{ marginRight: 8 }} /> Diário Emocional
          </button>
          <div className="search-container">
            <Search className="search-icon" size={18} />
            <input
              type="text"
              placeholder="Pesquisar registros..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="history-list">
          {filteredHistorico.map((item) => (
            <motion.div
              key={item.id}
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              className={`history-item ${sessaoAtiva?.id === item.id ? 'active' : ''}`}
              onClick={() => {
                selecionarSessao(item);
                setCurrentView('app');
              }}
            >
              <div className="history-item-content">
                <div className="date">
                  {item.data} • <span className={`sentiment-tag ${getSentimentClass(item.sentimento)}`}>{item.sentimento}</span>
                  <button className="delete-btn" onClick={(e) => deleteSessao(e, item.id)}>
                    <Trash2 size={14} />
                  </button>
                </div>
                <div className="preview">{item.transcricao}</div>
              </div>
            </motion.div>
          ))}
          {filteredHistorico.length === 0 && (
            <div className="status-text" style={{ textAlign: 'center', marginTop: '2rem' }}>
              Nenhum registro encontrado
            </div>
          )}
        </div>
      </aside>

      <main className="main-content">
        <AnimatePresence>
          {showSOS && <SOSOverlay />}
        </AnimatePresence>

        {currentView === 'dashboard' ? (
          DashboardView()
        ) : currentView === 'agenda' ? (
          <div className="app-container" style={{ maxWidth: '900px' }}>
            <header className="header" style={{ marginBottom: '1.5rem' }}>
              <h2 style={{ fontFamily: 'Outfit, sans-serif', fontSize: '2.5rem', fontWeight: '700' }}>Agendamento de Sessões</h2>
              <p style={{ color: 'var(--text-muted)' }}>Agende e gerencie suas consultas presenciais ou online</p>
            </header>
            {AgendaView()}
          </div>
        ) : currentView === 'financeiro' ? (
          <div className="app-container" style={{ maxWidth: '900px' }}>
            <header className="header" style={{ marginBottom: '1.5rem' }}>
              <h2 style={{ fontFamily: 'Outfit, sans-serif', fontSize: '2.5rem', fontWeight: '700' }}>Painel Financeiro</h2>
              <p style={{ color: 'var(--text-muted)' }}>Acompanhe seu saldo de sessões e histórico de faturas</p>
            </header>
            <FinanceiroView 
              usuario={usuario}
              API_BASE_URL={API_BASE_URL}
              pacienteSelecionado={pacienteSelecionado}
              financeiroData={financeiroData}
              setFinanceiroData={setFinanceiroData}
              listaPacotes={listaPacotes}
              fetchFinanceiro={fetchFinanceiro}
              fetchPacotes={fetchPacotes}
            />
          </div>
        ) : currentView === 'tarefas' ? (
          <div className="app-container" style={{ maxWidth: '900px' }}>
            <header className="header" style={{ marginBottom: '1.5rem' }}>
              <h2 style={{ fontFamily: 'Outfit, sans-serif', fontSize: '2.5rem', fontWeight: '700' }}>Minhas Tarefas</h2>
              <p style={{ color: 'var(--text-muted)' }}>Atividades e reflexões prescritas pelo seu terapeuta para realizar durante a semana</p>
            </header>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '1.25rem' }}>
              {carregandoTarefas ? (
                <p style={{ color: 'var(--text-muted)', textAlign: 'center' }}>Carregando atividades...</p>
              ) : listaTarefas.length === 0 ? (
                <div style={{ textAlign: 'center', padding: '4rem 1.5rem', background: 'rgba(255,255,255,0.02)', borderRadius: '1.5rem', border: '1px dashed rgba(255,255,255,0.1)' }}>
                  <ClipboardList size={40} style={{ color: 'var(--accent)', opacity: 0.3, marginBottom: '1rem', display: 'block', margin: '0 auto' }} />
                  <h4 style={{ color: 'white', marginBottom: '0.5rem' }}>Nenhuma tarefa pendente</h4>
                  <p style={{ color: 'var(--text-muted)', fontSize: '0.9rem', maxWidth: '400px', margin: '0 auto' }}>
                    Seu terapeuta irá prescrever exercícios ou leituras específicas por aqui quando necessário. Fique atento!
                  </p>
                </div>
              ) : (
                listaTarefas.map((tarefa) => (
                  <div key={tarefa.id} style={{
                    background: tarefa.concluida ? 'rgba(34, 197, 94, 0.02)' : 'rgba(15, 23, 42, 0.4)',
                    border: tarefa.concluida ? '1px solid rgba(34, 197, 94, 0.15)' : '1px solid var(--glass-border)',
                    padding: '1.5rem',
                    borderRadius: '1.2rem',
                    display: 'flex',
                    flexDirection: 'column',
                    gap: '12px',
                    transition: 'all 0.3s ease'
                  }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <h3 style={{ margin: 0, color: 'white', fontSize: '1.25rem', fontFamily: 'Outfit, sans-serif' }}>{tarefa.titulo}</h3>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                        <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>Criado em: {tarefa.data_criacao}</span>
                        {tarefa.concluida && (
                          <span style={{ fontSize: '0.7rem', background: 'rgba(34,197,94,0.15)', color: '#4ade80', padding: '2px 8px', borderRadius: '10px', fontWeight: 'bold' }}>Concluído</span>
                        )}
                      </div>
                    </div>

                    <p style={{
                      color: '#cbd5e1',
                      fontSize: '0.95rem',
                      lineHeight: '1.6',
                      margin: 0,
                      background: 'rgba(0,0,0,0.15)',
                      padding: '1rem',
                      borderRadius: '0.75rem',
                      whiteSpace: 'pre-wrap'
                    }}>
                      {tarefa.descricao}
                    </p>

                    <div style={{ display: 'flex', justifyContent: 'flex-end', alignItems: 'center', gap: '12px', borderTop: '1px solid rgba(255,255,255,0.05)', paddingTop: '10px', marginTop: '5px' }}>
                      {tarefa.concluida ? (
                        <>
                          <span style={{ fontSize: '0.8rem', color: '#4ade80' }}>Concluída em: {tarefa.data_conclusao}</span>
                          <button
                            onClick={() => handleConcluirTarefa(tarefa.id, false)}
                            style={{
                              background: 'rgba(239, 68, 68, 0.1)',
                              color: '#ef4444',
                              border: '1px solid rgba(239, 68, 68, 0.2)',
                              padding: '5px 12px',
                              borderRadius: '0.5rem',
                              fontSize: '0.8rem',
                              cursor: 'pointer'
                            }}
                          >
                            Refazer Tarefa
                          </button>
                        </>
                      ) : (
                        <button
                          onClick={() => handleConcluirTarefa(tarefa.id, true)}
                          style={{
                            background: 'var(--accent)',
                            color: 'white',
                            border: 'none',
                            padding: '8px 16px',
                            borderRadius: '0.5rem',
                            fontSize: '0.85rem',
                            fontWeight: 'bold',
                            cursor: 'pointer',
                            display: 'flex',
                            alignItems: 'center',
                            gap: '6px'
                          }}
                        >
                          Marcar como Concluída ✔️
                        </button>
                      )}
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        ) : currentView === 'diario' ? (
          <div className="app-container" style={{ maxWidth: '900px' }}>
            <header className="header" style={{ marginBottom: '1.5rem' }}>
              <h2 style={{ fontFamily: 'Outfit, sans-serif', fontSize: '2.5rem', fontWeight: '700' }}>Diário Emocional</h2>
              <p style={{ color: 'var(--text-muted)' }}>Acompanhe seu humor e seus sentimentos</p>
            </header>
            <DiarioEmocionalView usuario={usuario} API_BASE_URL={API_BASE_URL} pacienteSelecionado={null} />
          </div>
        ) : (
          <div className="app-container">
            <header className="header">
              <motion.h1
                initial={{ opacity: 0, y: -20 }}
                animate={{ opacity: 1, y: 0 }}
              >
                Psicólogo IA
              </motion.h1>
              <p className="status-text">Seu suporte profissional e preparação para terapia</p>
            </header>

            <motion.div
              className="main-card"
              layout
            >
              <section className="record-section">
                <button
                  className={`pulse-button ${gravando ? 'recording' : ''}`}
                  onClick={gravando ? pararGravacao : iniciarGravacao}
                  disabled={carregando}
                >
                  {gravando ? <Square size={48} /> : <Mic size={48} />}
                </button>
                <div className="status-container" style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                  <span className="status-text">
                    {gravando ? 'Ouvindo desabafo...' : carregando ? 'Atualizando prontuário...' : exercicio ? 'Clique para dar seguimento' : 'Clique para começar a falar'}
                  </span>
                  {exercicio && !carregando && !gravando && (
                    <button className="reset-btn" onClick={() => { setTranscricao(''); setExercicio(''); setSessaoAtiva(null); window.speechSynthesis.cancel(); }}>
                      Novo Desabafo
                    </button>
                  )}
                </div>
              </section>

              <AnimatePresence mode="wait">
                {(transcricao || exercicio || carregando) && (
                  <motion.section
                    className="result-section"
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                  >
                    <div className="result-card">
                      <h3><MessageSquare size={14} style={{ marginRight: 8 }} /> Seu Desabafo</h3>
                      <p>{carregando && !transcricao ? <span className="loading-dots">Transcrevendo áudio</span> : transcricao}</p>
                    </div>

                    {(exercicio || carregando) && (
                      <motion.div
                        className="result-card professional-card"
                        initial={{ opacity: 0, x: 20 }}
                        animate={{ opacity: 1, x: 0 }}
                      >
                        <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                          <h3 style={{ margin: 0, display: 'flex', alignItems: 'center' }}>
                            <Sparkles size={14} style={{ marginRight: 8 }} /> Análise e Preparação
                          </h3>
                          <div className="card-actions" style={{ display: 'flex', gap: '8px' }}>
                            {exercicio && (
                              <>
                                <button
                                  onClick={copiarParaPsicologo}
                                  className="audio-control-btn"
                                  title="Copiar Resumo para o Psicólogo"
                                  style={{ background: 'rgba(255,255,255,0.1)' }}
                                >
                                  <Calendar size={16} />
                                </button>
                                <button
                                  onClick={falando ? pararDeFalar : () => falar(exercicio)}
                                  className="audio-control-btn"
                                  title={falando ? "Parar áudio" : "Ouvir resposta"}
                                >
                                  {falando ? <Square size={16} fill="currentColor" /> : <Play size={16} fill="currentColor" />}
                                </button>
                              </>
                            )}
                          </div>
                        </div>
                        <div className="analysis-content">
                          {carregando && !exercicio ? (
                            <span className="loading-dots">Consultando abordagem terapêutica</span>
                          ) : (
                            formatarAnalise(exercicio)
                          )}
                        </div>
                      </motion.div>
                    )}
                  </motion.section>
                )}
              </AnimatePresence>
            </motion.div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
